Rule.Source:
import sailpoint.api.SailPointContext;
import sailpoint.object.Application;
import sailpoint.api.IdentityService;
import sailpoint.object.Identity;
import sailpoint.object.Link;
import sailpoint.object.ProvisioningPlan;
import sailpoint.object.ProvisioningPlan.AccountRequest;
import sailpoint.object.ProvisioningPlan.AttributeRequest;
import sailpoint.object.ProvisioningPlan.Operation;
import sailpoint.tools.GeneralException;
import sailpoint.tools.Util;
  
  import org.apache.commons.logging.Log;
  import org.apache.commons.logging.LogFactory;
  
  // Logic starts from here
  static Log logger = LogFactory.getLog("rule.Ascension-Rule-BeforeProvisioning-BadgeAccess");
  logger.debug("Entering Ascension-Rule-BeforeProvisioning-BadgeAccess");
  
  Identity identity = null;
   String requested_for = "";
  
  if (plan != null) {
    if(plan.get("requested_for")!=null && Util.isNotNullOrEmpty(plan.get("requested_for").toString()) ){
      requested_for = plan.get("requested_for").toString();
      identity = context.getObjectByName(Identity.class, requested_for);
    }
    if(identity !=null){
			if (plan.getAccountRequests() != null && plan.getAccountRequests(application.getName()) != null	&& !plan.getAccountRequests(application.getName()).isEmpty()) {
				for (AccountRequest accReq : plan.getAccountRequests(application.getName())) {
					if (accReq != null	&& accReq.getAttributeRequests() != null && !accReq.getAttributeRequests().isEmpty() && accReq.getOperation() != null && (AccountRequest.Operation.Create.equals(accReq.getOperation()) || AccountRequest.Operation.Modify.equals(accReq.getOperation())) ){
						

						
						if(accReq.getAttributeRequest("Manager Name")==null){
							if(identity.getManager()!=null && Util.isNotNullOrEmpty(identity.getManager().getDisplayName())){
								accReq.add(new AttributeRequest("Manager Name",Operation.Add,identity.getManager().getDisplayName()));
							}else {
								accReq.add(new AttributeRequest("Manager Name",Operation.Add,""));
							}
						}
						
				
						
						//Manager Contact Phone
						if(accReq.getAttributeRequest("Manager Contact Phone")==null){
							if(identity.getManager()!=null && Util.isNotNullOrEmpty(identity.getManager().getStringAttribute("telephoneNumber"))){
								accReq.add(new AttributeRequest("Manager Contact Phone",Operation.Add,identity.getManager().getStringAttribute("telephoneNumber")));
							}else {
								accReq.add(new AttributeRequest("Manager Contact Phone",Operation.Add,""));
							}
						}
						
						//Manager Contact Email
						if(accReq.getAttributeRequest("Manager Contact Email")==null){
							if(identity.getManager()!=null && Util.isNotNullOrEmpty(identity.getManager().getStringAttribute("email"))){
								accReq.add(new AttributeRequest("Manager Contact Email",Operation.Add,identity.getManager().getStringAttribute("email")));
							}else {
								accReq.add(new AttributeRequest("Manager Contact Email",Operation.Add,""));
							}
						}
						
						//Employee Name
						if(accReq.getAttributeRequest("Employee Name")==null){
							if(Util.isNotNullOrEmpty(identity.getDisplayName())){
								accReq.add(new AttributeRequest("Employee Name",Operation.Add,identity.getDisplayName()));
							}else {
								accReq.add(new AttributeRequest("Employee Name",Operation.Add,""));
							}
						}
						
				
						
						//Employee Contact Phone
						if(accReq.getAttributeRequest("Employee Contact Phone")==null){
							if(Util.isNotNullOrEmpty(identity.getStringAttribute("telephoneNumber"))){
								accReq.add(new AttributeRequest("Employee Contact Phone",Operation.Add,identity.getStringAttribute("telephoneNumber")));
							}else {
								accReq.add(new AttributeRequest("Employee Contact Phone",Operation.Add,""));
							}
						}
						
						//Employee Contact Email
						if(accReq.getAttributeRequest("Employee Contact Email")==null){
							if(Util.isNotNullOrEmpty(identity.getStringAttribute("email"))){
								accReq.add(new AttributeRequest("Employee Contact Email",Operation.Add,identity.getStringAttribute("email")));
							}else {
								accReq.add(new AttributeRequest("Employee Contact Email",Operation.Add,""));
							}
						}
             
            IdentityService iiqService = new IdentityService(context);
						List<Link> appLinks = iiqService.getLinks(identity, application);
						if(appLinks!=null && !appLinks.isEmpty()){
					
							
							//Existing Badge Number
							if(accReq.getAttributeRequest("Existing Badge Number")==null){
								String val = "";
								for(Link link : appLinks){
									if(link.getAttribute("Existing Badge Number")!=null){
										val = link.getAttribute("Existing Badge Number").toString();
									}
									if(Util.isNotNullOrEmpty(val)){
										break;
									}
								}
								if(Util.isNotNullOrEmpty(val)){
									accReq.add(new AttributeRequest("Existing Badge Number",Operation.Add,val));
								}else {
									accReq.add(new AttributeRequest("Existing Badge Number",Operation.Add,""));
								}
							}
						}
            
						
					}
				}
			}
     context.decache(identity);
    }
		}
  
  logger.debug("Exiting Ascension-Rule-BeforeProvisioning-BadgeAccess");
